import api from './api';

export const assureurAPI = {
  // Dashboard stats
  getStats: () => api.get('/assureur/stats'),

  // Dossiers
  getDossiers: (params = {}) => api.get('/assureur/dossiers', { params }),
  getDossierDetail: (id) => api.get(`/assureur/dossiers/${id}`),

  // Scores
  getScores: (params = {}) => api.get('/assureur/scores', { params }),

  // Devis
  getDevis: (params = {}) => api.get('/assureur/devis', { params }),
  validerDevis: (id) => api.put(`/assureur/devis/${id}/valider`),
  rejeterDevis: (id) => api.put(`/assureur/devis/${id}/rejeter`),

  // Analyses IA
  getAnalyses: (dossierId) => api.get(`/assureur/analyses/${dossierId}`),
};

export default assureurAPI;
